def adaptive_sort(values: Iterable[float], gas_left: int = DEFAULT_GAS) -> tuple[list[float], int]:
    records = [(sanitize(v), i) for i, v in enumerate(values)]
    if gas_left <= 0:
        return [v for v, _ in records], 1
    def learned_key(item):
        v, i = item
        return (v, 1e-9 * math.tanh(kernel(v + 0.001 * i, gas_left - 1)), i)
    out = [v for v, _ in sorted(records, key=learned_key)]
    if any(out[i] > out[i+1] for i in range(len(out)-1)):
        out = sorted(out)
    return out, 0

def graph_shortest_path(graph: dict, start, goal, gas_left: int = DEFAULT_GAS) -> tuple[dict, int]:
    import heapq
    dist = {start: 0.0}; parent = {}; heap = [(0.0, start)]
    seen = set()
    while heap:
        gas_left -= 1
        if gas_left <= 0:
            return {'path': [], 'cost': math.inf, 'reached': False}, 1
        cost, node = heapq.heappop(heap)
        if node in seen:
            continue
        seen.add(node)
        if node == goal:
            path = [node]
            while path[-1] in parent:
                path.append(parent[path[-1]])
            path.reverse()
            return {'path': path, 'cost': sanitize(cost), 'reached': True}, 0
        for nxt, w in graph.get(node, []):
            ww = abs(sanitize(w))
            priority_bias = 1e-6 * math.tanh(kernel(ww + len(seen), gas_left - 1))
            nc = cost + ww
            if nc < dist.get(nxt, math.inf):
                dist[nxt] = nc; parent[nxt] = node
                heapq.heappush(heap, (nc + priority_bias, nxt))
    return {'path': [], 'cost': math.inf, 'reached': False}, 0

def schedule_jobs(jobs: Iterable[float], workers: int = 2, gas_left: int = DEFAULT_GAS) -> tuple[dict, int]:
    workers = max(1, int(workers)); loads = [0.0] * workers; assignment = []
    ordered = [(sanitize(j), i) for i, j in enumerate(jobs)]
    ordered.sort(key=lambda p: -(abs(p[0]) + 0.01 * math.tanh(kernel(p[0], gas_left - 1))))
    for cost, idx in ordered:
        gas_left -= 1
        if gas_left <= 0:
            return {'assignment': assignment, 'loads': loads, 'makespan': max(loads) if loads else 0.0}, 1
        best = min(range(workers), key=lambda w: loads[w] + cost + 0.01 * math.tanh(kernel(loads[w] - cost, gas_left - 1)))
        loads[best] = sanitize(loads[best] + abs(cost)); assignment.append((idx, best))
    return {'assignment': sorted(assignment), 'loads': loads, 'makespan': max(loads), 'fairness': max(loads)-min(loads)}, 0

def parse_and_repair(tokens: Iterable[str], gas_left: int = DEFAULT_GAS) -> tuple[dict, int]:
    pairs = {')': '(', ']': '[', '}': '{'}; openers = set(pairs.values())
    stack = []; repairs = []; out = []
    for tok in tokens:
        gas_left -= 1
        if gas_left <= 0:
            return {'balanced': False, 'repairs': repairs, 'tokens': out}, 1
        if tok in openers:
            stack.append(tok); out.append(tok)
        elif tok in pairs:
            if stack and stack[-1] == pairs[tok]:
                stack.pop(); out.append(tok)
            else:
                repairs.append('insert_' + pairs[tok]); out.append(pairs[tok]); out.append(tok)
        else:
            out.append(tok)
    while stack:
        repairs.append('close_' + stack.pop())
    return {'balanced': len(repairs) == 0, 'repairs': repairs, 'tokens': out}, 0

def solve_constraints(domains: dict, constraints: list, gas_left: int = DEFAULT_GAS) -> tuple[dict, int]:
    vars_ = list(domains.keys())
    vars_.sort(key=lambda k: (len(domains[k]), math.tanh(kernel(len(domains[k]), gas_left - 1))))
    assign = {}
    def ok_partial():
        try:
            return all(c(assign) for c in constraints)
        except KeyError:
            return True
    def bt(i, gas):
        if gas <= 0: return False, gas
        if i == len(vars_): return all(c(assign) for c in constraints), gas
        v = vars_[i]
        vals = list(domains[v]); vals.sort(key=lambda x: math.tanh(kernel(sanitize(x), gas - 1)))
        for val in vals:
            assign[v] = val
            if ok_partial():
                done, gas = bt(i+1, gas-1)
                if done: return True, gas
            assign.pop(v, None)
        return False, gas
    done, gas_left = bt(0, gas_left)
    return ({'assignment': dict(assign), 'satisfied': bool(done)}, 0 if done else 4)

def stream_analyze(values: Iterable[float], gas_left: int = DEFAULT_GAS) -> tuple[dict, int]:
    n = 0; mean = 0.0; m2 = 0.0; anomalies = []
    for i, raw in enumerate(values):
        gas_left -= 1
        if gas_left <= 0:
            return {'count': n, 'mean': mean, 'variance': m2 / max(1, n-1), 'anomalies': anomalies}, 1
        x = sanitize(raw); n += 1
        delta = x - mean; mean += delta / n; m2 += delta * (x - mean)
        std = math.sqrt(max(1e-12, m2 / max(1, n-1)))
        score = abs(x - mean) / std + abs(math.tanh(kernel(x - mean, gas_left - 1)))
        if n > 4 and score > 3.0:
            anomalies.append((i, sanitize(score)))
    return {'count': n, 'mean': mean, 'variance': m2 / max(1, n-1), 'anomalies': anomalies}, 0

def compress_adaptive(values: Iterable[float], gas_left: int = DEFAULT_GAS) -> tuple[dict, int]:
    vals = [sanitize(v) for v in values]
    if not vals: return {'packets': [], 'decoded': [], 'ratio': 1.0}, 0
    packets = []; decoded = [] ; i = 0
    while i < len(vals):
        gas_left -= 1
        if gas_left <= 0: return {'packets': packets, 'decoded': decoded, 'ratio': 1.0}, 1
        base = vals[i]; run = 1; threshold = 1e-9 + 0.01 * abs(math.tanh(kernel(base, gas_left - 1)))
        while i + run < len(vals) and abs(vals[i+run] - base) <= threshold:
            run += 1
        packets.append(('run', base, run)); decoded.extend([base] * run); i += run
    raw = max(1, len(vals)); enc = max(1, len(packets) * 3)
    return {'packets': packets, 'decoded': decoded, 'ratio': enc / raw}, 0

def cache_simulate(requests: Iterable, capacity: int = 4, gas_left: int = DEFAULT_GAS) -> tuple[dict, int]:
    capacity = max(1, int(capacity)); cache = {}; hits = 0; misses = 0
    for t, r in enumerate(requests):
        gas_left -= 1
        if gas_left <= 0: return {'hits': hits, 'misses': misses, 'cache': list(cache.keys())}, 1
        if r in cache:
            hits += 1; cache[r]['freq'] += 1; cache[r]['last'] = t
        else:
            misses += 1
            if len(cache) >= capacity:
                victim = min(cache, key=lambda k: cache[k]['freq'] * 0.4 + cache[k]['last'] * 0.001 + 0.01 * math.tanh(kernel(cache[k]['freq'], gas_left - 1)))
                cache.pop(victim, None)
            cache[r] = {'freq': 1, 'last': t}
    return {'hits': hits, 'misses': misses, 'cache': list(cache.keys())}, 0

def load_balance(jobs: Iterable[float], workers: int = 2, gas_left: int = DEFAULT_GAS) -> tuple[dict, int]:
    return schedule_jobs(jobs, workers, gas_left)

def detect_anomalies(values: Iterable[float], gas_left: int = DEFAULT_GAS) -> tuple[list[int], int]:
    stats, err = stream_analyze(values, gas_left)
    return [i for i, _ in stats.get('anomalies', [])], err

